dtRows = dspblkGetFIRMultirateFiltersDTRowInfo();
if (FilterSource == 1) || (FilterSource == 4)
    s = dspblkfirdn2(gcbh,'icon',FilterSource,D);
    [a,dtInfo,framingSfunArg] = dspblkfirdn2(gcbh,'setup',FilterSource,dtRows,h,D,filtStruct,outputBufInitCond,framing,InputProcessing,AllowArbitraryInputLength);
elseif FilterSource == 2
    s = dspblkfirdn2(gcbh,'icon',FilterSource,D);
    [a,dtInfo,framingSfunArg] = dspblkfirdn2(gcbh,'setup',FilterSource,dtRows,D,filtStruct,outputBufInitCond,framing,InputProcessing,AllowArbitraryInputLength);
else
    s = dspblkfirdn2(gcbh,'icon',FilterSource,FilterObject);
    [a,dtInfo,framingSfunArg] = dspblkfirdn2(gcbh,'setup',FilterSource,FilterObject,framing,InputProcessing,AllowArbitraryInputLength);
end
dspblkfirdn2(gcbh,'init',FilterSource);

